  ('medical-tech-moex-21448', 'medical-tech', 'medical-tech-moex-092-aca0a627', 'sub-medical-tech-02', NULL, 'single_choice', '小腸如何吸收脂肪？ 以乳化油滴 (emulsion droplets) 的形式進入腸壁的細胞 以膠粒 (micelles) 的形式進入腸壁細胞 以個別的脂肪酸或monoglyceride的形式進入腸壁細胞 以chylomicron的形式進入腸壁細胞', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:18+00:00", "source_pdf_sha1": "caad7201cfd2", "answer_pdf_sha1": "f5d53904488e", "source_family": "moex-gov-tw", "moex": {"exam_code": "092170", "c": "105", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床生理學與病理學", "year": "092", "exam_name": "092年第二次醫事人員、中醫師、營養師、獸醫人員、心理師、呼吸治療師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
